from xarray.core.utils import compat_dict_union, dict_equiv, equivalent

def merge_attrs(variable_attrs, combine_attrs, context=None):
    """Combine attributes from different variables according to combine_attrs"""
    if not variable_attrs:
        return None
    if callable(combine_attrs):
        return combine_attrs(variable_attrs, context=context)
    elif combine_attrs == 'drop':
        return {}
    elif combine_attrs == 'override':
        return dict(variable_attrs[0])
    elif combine_attrs == 'no_conflicts':
        result = dict(variable_attrs[0])
        for attrs in variable_attrs[1:]:
            try:
                result = compat_dict_union(result, attrs)
            except ValueError as e:
                raise MergeError(f"combine_attrs='no_conflicts', but some values are not the same. Merging {str(result)} with {str(attrs)}") from e
        return result
    elif combine_attrs == 'drop_conflicts':
        result = {}
        dropped_keys = set()
        for attrs in variable_attrs:
            result.update({key: value for key, value in attrs.items() if key not in result and key not in dropped_keys})
            result = {key: value for key, value in result.items() if key not in attrs or equivalent(attrs[key], value)}
            dropped_keys |= {key for key in attrs if key not in result}
        return result
    elif combine_attrs == 'identical':
        result = dict(variable_attrs[0])
        for attrs in variable_attrs[1:]:
            if not dict_equiv(result, attrs):
                raise MergeError(f"combine_attrs='identical', but attrs differ. First is {str(result)} , other is {str(attrs)}.")
        return result
    else:
        raise ValueError(f'Unrecognised value for combine_attrs={combine_attrs}')
